// Build Target Matrix and convert to multiple items
const items = $input.all();
const input = items.length > 0 ? items[0].json : {};

// Extract optional runtime controls
const default_ref = input.ref || 'main';
const timeout_seconds = input.timeout_seconds || 3600;
const poll_interval_seconds = input.poll_interval_seconds || 30;  // Increased from 15 to 30 seconds to reduce API pressure
const fail_fast = input.fail_fast || false;
const selected_targets = input.selected_targets || null;

// Define normative six-target matrix
const full_matrix = [
  {"repo_owner":"NNTin","repo_name":"gSnake","workflow_path":".github/workflows/ci.yml","ref":"main","target_id":"gsnake-ci"},
  {"repo_owner":"NNTin","repo_name":"gsnake-web","workflow_path":".github/workflows/ci.yml","ref":"main","target_id":"gsnake-web-ci"},
  {"repo_owner":"NNTin","repo_name":"gsnake-specs","workflow_path":".github/workflows/ci.yml","ref":"main","target_id":"gsnake-specs-ci"},
  {"repo_owner":"NNTin","repo_name":"gsnake-levels","workflow_path":".github/workflows/ci.yml","ref":"main","target_id":"gsnake-levels-ci"},
  {"repo_owner":"NNTin","repo_name":"gsnake-editor","workflow_path":".github/workflows/ci.yml","ref":"main","target_id":"gsnake-editor-ci"},
  {"repo_owner":"NNTin","repo_name":"gsnake-specs","workflow_path":".github/workflows/test.yml","ref":"main","target_id":"gsnake-specs-test"}
];

// Apply selected_targets filter if provided
let targets = full_matrix;
if (selected_targets && Array.isArray(selected_targets) && selected_targets.length > 0) {
  targets = full_matrix.filter(t => selected_targets.includes(t.target_id));
}

// Store suite metadata and started_at timestamp
const started_at = new Date().toISOString();
const total_targets = targets.length;

console.log(`Built target matrix with ${total_targets} targets`);
console.log('Targets:', targets.map(t => t.target_id).join(', '));

// Output each target as a separate item with suite metadata attached
return targets.map(target => ({
  json: {
    ...target,
    ref: default_ref,
    timeout_seconds,
    poll_interval_seconds,
    request_id: `multi-ci-${started_at}-${target.target_id}`,
    // Suite metadata for aggregation
    _suite_started_at: started_at,
    _suite_total_targets: total_targets,
    _suite_fail_fast: fail_fast
  }
}));

// Extract target payload for child workflow (remove suite metadata)
const item = $input.first().json;

const target_payload = {
  repo_owner: item.repo_owner,
  repo_name: item.repo_name,
  workflow_path: item.workflow_path,
  ref: item.ref,
  timeout_seconds: item.timeout_seconds,
  poll_interval_seconds: item.poll_interval_seconds,
  request_id: item.request_id
};

console.log(`Executing target: ${item.target_id}`);

return [{ json: target_payload }];

// Normalize child output and merge with target metadata
const loop_item = $node['Loop Targets'].json;
const child_output = $input.first().json;

// Map child output to parent result schema
const result = {
  target_id: loop_item.target_id,
  repo_owner: loop_item.repo_owner,
  repo_name: loop_item.repo_name,
  workflow_path: loop_item.workflow_path,
  ref: loop_item.ref,
  status: child_output.status,
  request_id: loop_item.request_id
};

if (child_output.status === 'completed') {
  result.ci_success = child_output.ci_success;
  result.conclusion = child_output.conclusion;
  result.run_id = child_output.run?.id || null;
  result.run_url = child_output.run?.html_url || null;
} else if (child_output.status === 'error') {
  result.ci_success = null;
  result.error_code = child_output.error_code;
  result.error_message = child_output.message;
  result.retryable = child_output.retryable;
}

console.log(`Result for ${result.target_id}: status=${result.status}, ci_success=${result.ci_success}`);

// Attach suite metadata for final aggregation
result._suite_started_at = loop_item._suite_started_at;
result._suite_total_targets = loop_item._suite_total_targets;
result._suite_fail_fast = loop_item._suite_fail_fast;

// Check fail_fast condition
if (loop_item._suite_fail_fast) {
  const is_failure = result.status === 'error' || (result.status === 'completed' && !result.ci_success);
  if (is_failure) {
    console.log('Fail-fast triggered for', result.target_id);
    result._should_stop = true;
  }
}

return [{ json: result }];

// Aggregate Suite Summary from all result items
const items = $input.all();

if (items.length === 0) {
  return [{
    json: {
      status: 'error',
      error_code: 'NO_RESULTS',
      message: 'No targets were executed',
      overall_success: false
    }
  }];
}

// Extract suite metadata from first item
const first_item = items[0].json;
const started_at = first_item._suite_started_at;
const total_targets = first_item._suite_total_targets;

console.log(`Aggregating results for ${items.length} executed targets out of ${total_targets} total`);

// Compute summary counts
let passed = 0;
let failed = 0;
let errors = 0;

const results = [];

for (const item of items) {
  const result = { ...item.json };

  // Remove internal metadata
  delete result._suite_started_at;
  delete result._suite_total_targets;
  delete result._suite_fail_fast;
  delete result._should_stop;

  results.push(result);

  // Count by status
  if (result.status === 'completed') {
    if (result.ci_success === true) {
      passed += 1;
    } else {
      failed += 1;
    }
  } else if (result.status === 'error') {
    errors += 1;
  }
}

const overall_success = (failed === 0 && errors === 0);

const finished_at = new Date().toISOString();
const start = new Date(started_at);
const end = new Date(finished_at);
const duration_seconds = Math.floor((end - start) / 1000);

const output = {
  status: 'completed',
  overall_success,
  summary: {
    total: total_targets,
    passed,
    failed,
    errors
  },
  results,
  started_at,
  finished_at,
  duration_seconds
};

console.log('Suite Summary:', output.summary);
console.log('Overall Success:', output.overall_success);
console.log('Duration:', duration_seconds, 'seconds');

return [{ json: output }];
